import React from 'react';
import { useForm } from 'react-hook-form';

function RegisterPage() {
    const {register, handleSubmit, formState: { errors }} = useForm();


    function SumbitForm(data) {
        console.log(data); 
        // { username: 'test', email: 'test', password: 'test' }
        }

    return (
        <form onSubmit={handleSubmit(SumbitForm)}>
            <input {...register('LoginName')} />
            <input {...register('PasswordName', { required: true })} />
            <input {...register('ConfirmPasswordName', { required: true })} />
            {errors.PasswordName && <p>Password is required.</p>}
            {errors.ConfirmPasswordName && <p>Confirm password is required.</p>}
            <button type="submit" disabled={formState.isSubmitting}>Зарегестрироваться</button>
        </form>
    );
}

export default RegisterPage;
